/* Agent Elements tokens + utilities */

/*
 * AN Agent Chat - CSS Custom Properties
 * These are the default values. Override by redefining these vars in your app CSS.
 */
:root {
  /* Geometry — all radii derive from --an-border-radius */
  --an-border-radius: 16px;
  --an-message-border-radius: var(--an-border-radius);
  --an-input-border-radius: var(--an-border-radius);
  --an-tool-border-radius: 10px;
  --an-message-radius-inner-offset: 4px;
  --an-max-width: 420px;

  /* Colors - Light mode defaults */
  --an-background: #ffffff;
  --an-background-secondary: #f0f0f0;
  --an-background-tertiary: #f8f8f8;
  --an-foreground: #1a1a1a;
  --an-foreground-muted: #737373;
  --an-foreground-subtle: #a3a3a3;
  --an-border-color: #e4e4e7;
  --an-primary-color: #3b82f6;

  /* User Messages */
  --an-user-message-bg: #f5f5f5;
  --an-user-message-text: #1a1a1a;

  /* Input */
  --an-input-background: #ffffff;
  --an-input-border-color: #e4e4e7;
  --an-input-color: #1a1a1a;
  --an-input-placeholder-color: #a3a3a3;
  --an-input-focus-outline: transparent;
  --an-context-padding: 10px;

  /* Send/Stop Buttons */
  --an-send-button-bg: #3b82f6;
  --an-send-button-color: #ffffff;

  /* Tools */
  --an-tool-background: #f5f5f5;
  --an-tool-border-color: #e4e4e7;
  --an-tool-color: #1a1a1a;
  --an-tool-color-muted: #737373;

  /* Code */
  --an-code-background: #1e1e1e;
  --an-code-color: #d4d4d4;

  /* Diff colors */
  --an-diff-added-bg: rgba(34, 197, 94, 0.1);
  --an-diff-added-border: rgba(34, 197, 94, 0.5);
  --an-diff-added-text: #15803d;
  --an-diff-removed-bg: rgba(239, 68, 68, 0.1);
  --an-diff-removed-border: rgba(239, 68, 68, 0.5);
  --an-diff-removed-text: #dc2626;
}

/* Dark mode defaults */
.dark {
  --an-background: #0a0a0a;
  --an-background-secondary: #242424;
  --an-background-tertiary: #141414;
  --an-foreground: #fafafa;
  --an-foreground-muted: #8c8c8c;
  --an-foreground-subtle: #71717a;
  --an-border-color: #2a2a2a;
  --an-primary-color: #60a5fa;

  --an-user-message-bg: #1a1a1a;
  --an-user-message-text: #fafafa;

  --an-input-background: #0a0a0a;
  --an-input-border-color: #2a2a2a;
  --an-input-color: #fafafa;
  --an-input-placeholder-color: #71717a;
  --an-input-focus-outline: transparent;
  --an-context-padding: 12px;

  --an-send-button-bg: #60a5fa;
  /* Dark mode uses a lighter primary (#60a5fa) — pair it with black text so
     labels like "Approve" / send-arrow have proper contrast instead of
     low-contrast white-on-light-blue. */
  --an-send-button-color: #0a0a0a;

  --an-tool-background: #141414;
  --an-tool-border-color: #2a2a2a;
  --an-tool-color: #fafafa;
  --an-tool-color-muted: #8c8c8c;

  --an-code-background: #0a0a0a;
  --an-code-color: #d4d4d4;

  --an-diff-added-bg: rgba(34, 197, 94, 0.15);
  --an-diff-added-border: rgba(34, 197, 94, 0.4);
  --an-diff-added-text: #4ade80;
  --an-diff-removed-bg: rgba(239, 68, 68, 0.15);
  --an-diff-removed-border: rgba(239, 68, 68, 0.4);
  --an-diff-removed-text: #f87171;
}

/* Dark mode via system preference — mirrors the `.dark` block above so that
   when nexUI is on its default "System" theme (no explicit `.dark` class on
   the html root) and the OS prefers dark, the --an-* tool tokens flip too.
   Without this block, tool cards (mcp-tool, plan-tool, todo-tool, bash-tool,
   edit-tool, question-tool, etc.) would render with light-mode surfaces and
   dark text while the rest of the page is in dark mode.

   `:root:not(.light)` matches the same scope nexUI's globals.css uses, so an
   explicit `.light` class on root still wins. */
@media (prefers-color-scheme: dark) {
  :root:not(.light) {
    --an-background: #0a0a0a;
    --an-background-secondary: #242424;
    --an-background-tertiary: #141414;
    --an-foreground: #fafafa;
    --an-foreground-muted: #8c8c8c;
    --an-foreground-subtle: #71717a;
    --an-border-color: #2a2a2a;
    --an-primary-color: #60a5fa;

    --an-user-message-bg: #1a1a1a;
    --an-user-message-text: #fafafa;

    --an-input-background: #0a0a0a;
    --an-input-border-color: #2a2a2a;
    --an-input-color: #fafafa;
    --an-input-placeholder-color: #71717a;
    --an-input-focus-outline: transparent;
    --an-context-padding: 12px;

    --an-send-button-bg: #60a5fa;
    --an-send-button-color: #0a0a0a;

    --an-tool-background: #141414;
    --an-tool-border-color: #2a2a2a;
    --an-tool-color: #fafafa;
    --an-tool-color-muted: #8c8c8c;

    --an-code-background: #0a0a0a;
    --an-code-color: #d4d4d4;

    --an-diff-added-bg: rgba(34, 197, 94, 0.15);
    --an-diff-added-border: rgba(34, 197, 94, 0.4);
    --an-diff-added-text: #4ade80;
    --an-diff-removed-bg: rgba(239, 68, 68, 0.15);
    --an-diff-removed-border: rgba(239, 68, 68, 0.4);
    --an-diff-removed-text: #f87171;
  }
}

@theme inline {
  --color-an-background: var(--an-background);
  --color-an-background-secondary: var(--an-background-secondary);
  --color-an-background-tertiary: var(--an-background-tertiary);
  --color-an-foreground: var(--an-foreground);
  --color-an-foreground-muted: var(--an-foreground-muted);
  --color-an-foreground-subtle: var(--an-foreground-subtle);
  --color-an-border-color: var(--an-border-color);
  --color-an-primary-color: var(--an-primary-color);
  --color-an-user-message-bg: var(--an-user-message-bg);
  --color-an-user-message-text: var(--an-user-message-text);
  --color-an-input-background: var(--an-input-background);
  --color-an-input-border-color: var(--an-input-border-color);
  --color-an-input-color: var(--an-input-color);
  --color-an-input-placeholder-color: var(--an-input-placeholder-color);
  --color-an-input-focus-outline: var(--an-input-focus-outline);
  --color-an-send-button-bg: var(--an-send-button-bg);
  --color-an-send-button-color: var(--an-send-button-color);
  --color-an-tool-background: var(--an-tool-background);
  --color-an-tool-border-color: var(--an-tool-border-color);
  --color-an-tool-color: var(--an-tool-color);
  --color-an-tool-color-muted: var(--an-tool-color-muted);
  --color-an-code-background: var(--an-code-background);
  --color-an-code-color: var(--an-code-color);
  --color-an-diff-added-bg: var(--an-diff-added-bg);
  --color-an-diff-added-border: var(--an-diff-added-border);
  --color-an-diff-added-text: var(--an-diff-added-text);
  --color-an-diff-removed-bg: var(--an-diff-removed-bg);
  --color-an-diff-removed-border: var(--an-diff-removed-border);
  --color-an-diff-removed-text: var(--an-diff-removed-text);
  --radius-an-message: var(--an-message-border-radius);
  --radius-an-message-inner: calc(
    var(--an-message-border-radius) - var(--an-message-radius-inner-offset)
  );
  --radius-an-input-border-radius: var(--an-input-border-radius);
  --radius-an-tool-border-radius: var(--an-tool-border-radius);
  --spacing-an-context-padding: var(--an-context-padding);
  --max-width-an: var(--an-max-width);
  --spacing-an-user-message-x: 14px;
  --spacing-an-user-message-y: 10px;
}

/* TextShimmer animation */
@keyframes an-shimmer {
  from {
    background-position: 100% center;
  }
  to {
    background-position: 0% center;
  }
}

@keyframes an-blink {
  50% {
    opacity: 0;
  }
}

@keyframes loading-dots {
  0%,
  100% {
    opacity: 0;
  }
  50% {
    opacity: 1;
  }
}

@keyframes an-ellipsis {
  0% {
    width: 0;
  }
  33% {
    width: 0.33em;
  }
  66% {
    width: 0.66em;
  }
  100% {
    width: 1em;
  }
}

.an-text-shimmer {
  display: inline-block;
  background-size: 250% 100%;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  background-image: linear-gradient(
    90deg,
    var(--an-foreground-subtle, #a3a3a3) 0%,
    var(--an-foreground-subtle, #a3a3a3) 40%,
    var(--an-foreground-muted, #737373) 50%,
    var(--an-foreground-subtle, #a3a3a3) 60%,
    var(--an-foreground-subtle, #a3a3a3) 100%
  );
  background-repeat: no-repeat;
}

.an-text-shimmer--active {
  animation: an-shimmer var(--an-shimmer-duration, 2s) linear infinite;
}

.an-ellipsis {
  display: inline-block;
  overflow: hidden;
  width: 0;
  vertical-align: bottom;
  animation: an-ellipsis 1.2s steps(1, end) infinite;
}

.an-markdown pre code {
  counter-reset: none !important;
}

.an-markdown pre code > span::before {
  content: none !important;
  display: none !important;
}

.an-markdown pre code > span {
  padding-left: 0 !important;
}

/* Diff */
.an-edit-diff,
.an-edit-diff pre,
.an-edit-diff code {
  font-size: 12px;
}

.dark .an-edit-tool-card,
[data-theme="dark"] .an-edit-tool-card {
  background-color: #000;
}

.dark .an-edit-tool-card .an-edit-diff,
.dark .an-edit-tool-card .an-edit-diff pre,
.dark .an-edit-tool-card .an-edit-diff code,
[data-theme="dark"] .an-edit-tool-card .an-edit-diff,
[data-theme="dark"] .an-edit-tool-card .an-edit-diff pre,
[data-theme="dark"] .an-edit-tool-card .an-edit-diff code {
  background-color: #000 !important;
}

/* System-preference dark mode equivalents — match nexUI's :root:not(.light)
   scope so they trigger when no explicit theme class is set. */
@media (prefers-color-scheme: dark) {
  :root:not(.light) .an-edit-tool-card {
    background-color: #000;
  }

  :root:not(.light) .an-edit-tool-card .an-edit-diff,
  :root:not(.light) .an-edit-tool-card .an-edit-diff pre,
  :root:not(.light) .an-edit-tool-card .an-edit-diff code {
    background-color: #000 !important;
  }
}

/* Markdown Code Block */
.an-markdown [data-streamdown="code-block"] {
  padding: 0;
  border: 1px solid var(--an-border-color);
  border-radius: var(--an-tool-border-radius);
  background: transparent;
  gap: 0;
}

.an-markdown [data-streamdown="code-block-header"] {
  padding: 0px 10px 0px 8px;
  height: auto;
  font-size: 12px;
  height: 28px;
  background: transparent;
  border-bottom: 1px solid var(--color-an-tool-border-color);
  background-color: var(--an-tool-background);
  position: relative;
}

.an-markdown div:has(> [data-streamdown="code-block-actions"]) {
  position: absolute;
  height: auto;
  margin: 0;
  top: 0;
  right: 0;
  height: 28px;
  padding-right: 8px;
}

.an-markdown [data-streamdown="code-block-actions"] {
  background: transparent;
  border: none;
  backdrop-filter: none;
  padding: 0;
}

.an-markdown [data-streamdown="code-block-actions"] button > svg {
  width: 14px;
  height: 14px;
}

.an-markdown [data-streamdown="code-block-body"] {
  margin: 0;
  padding-top: 8px;
  padding-bottom: 8px;
  background: transparent;
  border: transparent;
  overflow-x: auto;
}

.an-markdown [data-streamdown="code-block"] pre,
.an-markdown [data-streamdown="code-block"] code {
  font-size: 12px;
  background: transparent;
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// WCAG relative luminance from sRGB hex
export function luminance(hex: string): number {
  const c = hex.replace("#", "");
  const r = parseInt(c.slice(0, 2), 16) / 255;
  const g = parseInt(c.slice(2, 4), 16) / 255;
  const b = parseInt(c.slice(4, 6), 16) / 255;
  const toLinear = (v: number) =>
    v <= 0.03928 ? v / 12.92 : ((v + 0.055) / 1.055) ** 2.4;
  return 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
}

/** Try to normalize a CSS color string to a 6-digit hex. Returns null on failure. */
function toHex6(color: string): string | null {
  const trimmed = color.trim();

  // #RRGGBB
  if (/^#[0-9a-fA-F]{6}$/.test(trimmed)) return trimmed;

  // #RGB → #RRGGBB
  const short = trimmed.match(/^#([0-9a-fA-F])([0-9a-fA-F])([0-9a-fA-F])$/);
  if (short)
    return `#${short[1]}${short[1]}${short[2]}${short[2]}${short[3]}${short[3]}`;

  // #RRGGBBAA → strip alpha
  if (/^#[0-9a-fA-F]{8}$/.test(trimmed)) return trimmed.slice(0, 7);

  // rgb(r, g, b) or rgba(r, g, b, a)
  const rgb = trimmed.match(/^rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
  if (rgb) {
    const hex = (n: string) => parseInt(n).toString(16).padStart(2, "0");
    return `#${hex(rgb[1])}${hex(rgb[2])}${hex(rgb[3])}`;
  }

  return null;
}

// Returns contrasting text color for a given background color
export function contrastText(bg: string): string {
  if (!bg) return "inherit";
  const hex = toHex6(bg);
  if (!hex) return "inherit";
  return luminance(hex) > 0.179 ? "#1a1a1a" : "#ffffff";
}

/**
 * Tool state cache for detecting AI SDK in-place mutations.
 * AI SDK mutates objects in-place during streaming, so we must
 * cache state externally and compare cached values.
 */

type CachedToolState = {
  state: string | undefined;
  inputJson: string;
  outputJson: string;
};

const toolStateCache = new Map<string, CachedToolState>();

function getToolStateSnapshot(part: any): CachedToolState {
  return {
    state: part.state,
    inputJson: JSON.stringify(part.input || {}),
    outputJson: JSON.stringify(part.output || {}),
  };
}

function hasToolStateChanged(toolCallId: string, part: any): boolean {
  const cached = toolStateCache.get(toolCallId);
  const current = getToolStateSnapshot(part);

  if (!cached) {
    toolStateCache.set(toolCallId, current);
    return true;
  }

  const changed =
    cached.state !== current.state ||
    cached.inputJson !== current.inputJson ||
    cached.outputJson !== current.outputJson;

  if (changed) {
    toolStateCache.set(toolCallId, current);
  }

  return changed;
}

function arePartsEqual(prev: any, next: any): boolean {
  if (prev.toolCallId !== next.toolCallId) return false;
  if (prev.type !== next.type) return false;

  const toolCallId = next.toolCallId;
  if (!toolCallId) {
    return prev.state === next.state;
  }

  const changed = hasToolStateChanged(toolCallId, next);
  return !changed;
}

function isToolCompleted(part: any): boolean {
  if (part.output !== undefined && part.output !== null) return true;
  if (part.state === "error") return true;
  if (part.state === "result") return true;
  return false;
}

/** Deep compare function for tool part props. Used with React.memo(). */
export function areToolPropsEqual(
  prevProps: { part: any; chatStatus?: string },
  nextProps: { part: any; chatStatus?: string },
): boolean {
  const partsEqual = arePartsEqual(prevProps.part, nextProps.part);
  if (!partsEqual) return false;
  if (isToolCompleted(nextProps.part)) return true;
  if (prevProps.chatStatus !== nextProps.chatStatus) return false;
  return true;
}

/** Get tool status from part state */
export function getToolStatus(part: any, chatStatus?: string) {
  const basePending =
    part.state !== "output-available" && part.state !== "output-error";
  const isError =
    part.state === "output-error" ||
    (part.state === "output-available" && part.output?.success === false);
  const isSuccess = part.state === "output-available" && !isError;
  const isPending = basePending && chatStatus === "streaming";
  const isInterrupted =
    basePending && chatStatus !== "streaming" && chatStatus !== undefined;

  return { isPending, isError, isSuccess, isInterrupted };
}

const SYSTEM_FONTS = new Set([
  "ui-sans-serif",
  "system-ui",
  "-apple-system",
  "BlinkMacSystemFont",
  "Segoe UI",
  "Roboto",
  "Helvetica Neue",
  "Arial",
  "Noto Sans",
  "ui-serif",
  "Georgia",
  "Cambria",
  "Times New Roman",
  "Times",
  "ui-monospace",
  "SFMono-Regular",
  "Menlo",
  "Monaco",
  "Consolas",
  "Liberation Mono",
  "Courier New",
  "serif",
  "sans-serif",
  "monospace",
]);

export function loadGoogleFont(fontFamily: string) {
  if (!fontFamily) return;
  const name = fontFamily.split(",")[0]!.trim().replace(/['"]/g, "");
  if (!name || SYSTEM_FONTS.has(name)) return;

  const encoded = encodeURIComponent(name);
  if (document.querySelector(`link[href*="${encoded}"]`)) return;

  const link = document.createElement("link");
  link.href = `https://fonts.googleapis.com/css2?family=${encoded}:wght@400;500;600;700&display=swap`;
  link.rel = "stylesheet";
  link.type = "text/css";
  document.head.appendChild(link);
}

import type { TimelineStep, StepState } from "../types/timeline";

function calculateDiffStatsFromPatch(
  patches: Array<{ lines?: string[] }>,
): string | undefined {
  let addedLines = 0;
  let removedLines = 0;

  for (const patch of patches) {
    if (!patch.lines) continue;
    for (const line of patch.lines) {
      if (line.startsWith("+")) addedLines++;
      else if (line.startsWith("-")) removedLines++;
    }
  }

  if (addedLines === 0 && removedLines === 0) return undefined;

  const parts: string[] = [];
  if (addedLines > 0) parts.push(`+${addedLines}`);
  if (removedLines > 0) parts.push(`-${removedLines}`);
  return parts.join(" ");
}

function getDiffLinesFromPatch(
  patches: Array<{ lines?: string[] }>,
): { type: "add" | "remove" | "context"; content: string }[] {
  const result: { type: "add" | "remove" | "context"; content: string }[] = [];

  for (const patch of patches) {
    if (!patch.lines) continue;
    for (const line of patch.lines) {
      if (line.startsWith("+")) {
        result.push({ type: "add", content: line.slice(1) });
      } else if (line.startsWith("-")) {
        result.push({ type: "remove", content: line.slice(1) });
      } else if (line.startsWith(" ")) {
        result.push({ type: "context", content: line.slice(1) });
      }
    }
  }

  return result;
}

export function mapToolStateToStepState(
  aiState: "partial-call" | "call" | "result",
): StepState {
  return aiState === "result" ? "complete" : "animating";
}

export function mapToolNameToVariant(
  toolName: string,
): "thinking" | "action" | "search" | undefined {
  const lower = toolName.toLowerCase();
  if (lower === "thinking" || lower === "reasoning") return "thinking";
  if (
    lower === "websearch" ||
    lower === "web_search" ||
    lower === "grep" ||
    lower === "glob" ||
    lower === "webfetch" ||
    lower === "web_fetch"
  )
    return "search";
  return undefined;
}

function extractToolDetail(
  toolName: string,
  args: Record<string, any>,
): string {
  switch (toolName) {
    case "Bash":
      return args?.command ? String(args.command).slice(0, 80) : "";
    case "Edit":
    case "Write":
    case "Read":
      return args?.file_path
        ? (String(args.file_path).split("/").pop() ?? "")
        : "";
    case "Grep":
      return args?.pattern ? String(args.pattern) : "";
    case "Glob":
      return args?.pattern ? String(args.pattern) : "";
    case "WebSearch":
    case "web_search":
      return args?.query ? String(args.query) : "";
    case "WebFetch":
    case "web_fetch":
      return args?.url ? String(args.url).slice(0, 60) : "";
    default:
      return "";
  }
}

export function mapToolInvocationToStep(
  toolCallId: string,
  toolInvocation: {
    toolName: string;
    args?: Record<string, any>;
    state: "partial-call" | "call" | "result";
    result?: any;
  },
): Extract<TimelineStep, { type: "tool-call" }> {
  const { toolName, args = {}, result } = toolInvocation;
  const displayToolName =
    toolName === "PlanWrite"
      ? "Plan"
      : toolName === "TodoWrite"
        ? "Todo"
        : toolName;
  const detail = extractToolDetail(toolName, args);

  const step: Extract<TimelineStep, { type: "tool-call" }> = {
    id: toolCallId,
    type: "tool-call",
    toolName: displayToolName,
    toolDetail: detail,
    duration: Number.MAX_SAFE_INTEGER,
    toolVariant: mapToolNameToVariant(toolName),
  };

  if (toolName === "Bash") {
    step.bashCommand = args?.command ? String(args.command) : undefined;
    if (toolInvocation.state === "result" && result) {
      if (typeof result === "string") {
        step.bashOutput = result;
        step.bashSuccess = true;
      } else if (typeof result === "object") {
        const stdout =
          typeof result?.stdout === "string"
            ? result.stdout
            : typeof result?.output === "string"
              ? result.output
              : "";
        const stderr = typeof result?.stderr === "string" ? result.stderr : "";
        step.bashOutput = [stdout, stderr]
          .filter(Boolean)
          .join(stdout && stderr ? "\n" : "");
        const exitCode = result?.exitCode ?? result?.exit_code;
        step.bashSuccess = exitCode === undefined ? true : exitCode === 0;
      } else {
        step.bashOutput = JSON.stringify(result);
        step.bashSuccess = true;
      }
    }
  }

  if (toolName === "Edit" || toolName === "Write" || toolName === "Read") {
    step.filePath = args?.file_path ? String(args.file_path) : undefined;
  }

  if (toolName === "Write") {
    const content =
      typeof result?.content === "string"
        ? result.content
        : typeof args?.content === "string"
          ? args.content
          : "";

    if (content) {
      const lines = content.split("\n");
      step.diffStats = `+${lines.length}`;
      step.diffLines = lines.map((line: string) => ({
        type: "add",
        content: line,
      }));
    }
  }

  if (toolName === "Edit" && Array.isArray(result?.structuredPatch)) {
    step.diffStats = calculateDiffStatsFromPatch(result.structuredPatch);
    step.diffLines = getDiffLinesFromPatch(result.structuredPatch);
  }

  if (
    toolName === "WebSearch" ||
    toolName === "web_search" ||
    toolName === "Grep" ||
    toolName === "Glob"
  ) {
    step.searchQuery =
      (args?.query ?? args?.pattern)
        ? String(args?.query ?? args?.pattern)
        : undefined;
    step.searchSource =
      toolName === "WebSearch" || toolName === "web_search" ? "web" : "code";
  }

  if (
    toolName.toLowerCase() === "thinking" ||
    toolName.toLowerCase() === "reasoning"
  ) {
    step.thoughtContent =
      typeof args?.thought === "string"
        ? args.thought
        : typeof result === "string"
          ? result
          : undefined;
  }

  return step;
}

type AnyRecord = Record<string, any>;

function isRecord(value: unknown): value is AnyRecord {
  return typeof value === "object" && value !== null;
}

function parseStructuredJson(value: unknown): unknown {
  if (typeof value !== "string") return value;
  const trimmed = value.trim();
  if (!trimmed) return value;

  try {
    const parsed = JSON.parse(trimmed);
    return isRecord(parsed) || Array.isArray(parsed) ? parsed : value;
  } catch {
    return value;
  }
}

export function normalizeToolPart(part: unknown): unknown {
  if (!isRecord(part)) return part;
  if (typeof part.type !== "string" || !part.type.startsWith("tool-"))
    return part;

  const normalizedInput = parseStructuredJson(part.input);
  const normalizedOutput = parseStructuredJson(part.output);
  const normalizedResult = parseStructuredJson(part.result);

  const inputChanged = normalizedInput !== part.input;
  const outputChanged = normalizedOutput !== part.output;
  const resultChanged = normalizedResult !== part.result;

  if (!inputChanged && !outputChanged && !resultChanged) {
    return part;
  }

  const normalizedPart: AnyRecord = { ...part };
  if (inputChanged) normalizedPart.input = normalizedInput;
  if (outputChanged) normalizedPart.output = normalizedOutput;
  if (resultChanged) normalizedPart.result = normalizedResult;
  return normalizedPart;
}

export function normalizeAssistantToolParts(parts: unknown[]): unknown[] {
  let changed = false;
  const normalizedParts = parts.map((part) => {
    const normalizedPart = normalizeToolPart(part);
    if (normalizedPart !== part) changed = true;
    return normalizedPart;
  });

  return changed ? normalizedParts : parts;
}

import { useState, useEffect, useCallback, useRef, useMemo } from "react";

export function useStreamingText(
  fullText: string,
  options: {
    delayBefore?: number;
    wordInterval?: number;
    autoStart?: boolean;
    onComplete?: () => void;
    onUpdate?: () => void;
  } = {},
) {
  const {
    delayBefore = 300,
    wordInterval = 25,
    autoStart = true,
    onComplete,
    onUpdate,
  } = options;
  const [state, setState] = useState<"idle" | "streaming" | "complete">("idle");
  const [visibleCount, setVisibleCount] = useState(0);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const onCompleteRef = useRef(onComplete);
  const onUpdateRef = useRef(onUpdate);
  onCompleteRef.current = onComplete;
  onUpdateRef.current = onUpdate;

  const tokens = useMemo(() => fullText.split(/(\s+)/), [fullText]);

  const cleanup = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
  }, []);

  const startStreaming = useCallback(() => {
    cleanup();
    setVisibleCount(0);
    setState("idle");
    timeoutRef.current = setTimeout(() => {
      setState("streaming");
      let count = 0;
      let updateThrottle = 0;
      intervalRef.current = setInterval(() => {
        count++;
        setVisibleCount(count);
        updateThrottle++;
        if (updateThrottle % 3 === 0) onUpdateRef.current?.();
        if (count >= tokens.length) {
          if (intervalRef.current) clearInterval(intervalRef.current);
          setState("complete");
          onCompleteRef.current?.();
        }
      }, wordInterval);
    }, delayBefore);
  }, [tokens, delayBefore, wordInterval, cleanup]);

  useEffect(() => {
    if (autoStart) startStreaming();
    return cleanup;
  }, [autoStart, startStreaming, cleanup]);

  return {
    displayedText: tokens.slice(0, visibleCount).join(""),
    tokens,
    visibleCount,
    state,
    isStreaming: state === "streaming",
  };
}

import { useEffect, useRef } from "react";

export function useToolComplete(
  isAnimating: boolean,
  duration: number,
  onComplete: () => void,
) {
  const onCompleteRef = useRef(onComplete);
  onCompleteRef.current = onComplete;

  useEffect(() => {
    if (!isAnimating) return;
    const t = setTimeout(() => onCompleteRef.current(), duration);
    return () => clearTimeout(t);
  }, [isAnimating, duration]);
}

